css:
.loader {color: var(--loader-color, #e11d48);
  --loader-secondary-color: #fb7185;
  --loader-bg: #ffffff;
  height: 64px;
  aspect-ratio: 1.5;
  display: flex;
  gap: 8px;
}.loader:before,.loader:after {content: "";
  border: 8px solid var(--loader-color, #e11d48);
  border-radius: 50%;
  box-sizing: content-box;
  margin: auto;
  aspect-ratio: 1;
  animation: l9 infinite 1s steps(4,jump-none);
}.loader:before {animation-direction: reverse;
}@keyframes l9 {0% {width: 0% }to {width: 75%}}
